args.sparql:
SELECT ?player ?playerLabel WHERE {
  wd:Q575370 p:P634 ?captainStatement .
  ?captainStatement ps:P634 ?player .
  ?player rdfs:label ?playerLabel .
  FILTER(LANG(?playerLabel) = "en")
}

SELECT ?player ?playerLabel WHERE {
  ?player p:P54 ?membership .
  ?membership ps:P54 wd:Q575370 ;
              pq:P39 wd:Q1920825 ;
              pq:P580 ?start ;
              pq:P582 ?end .
  FILTER(ql:overlaps(?start, ?end, "2009-01-01T00:00:00Z"^^xsd:dateTime, "2013-12-31T00:00:00Z"^^xsd:dateTime))
  ?player rdfs:label ?playerLabel .
  FILTER(LANG(?playerLabel) = "en")
}

SELECT ?player ?playerLabel WHERE {
  ?player p:P54 ?membership .
  ?membership ps:P54 wd:Q575370 ;
              pq:P39 wd:Q1920825 ;
              pq:P580 ?start ;
              pq:P582 ?end .
  FILTER (?start <= "2013-12-31T00:00:00Z"^^xsd:dateTime &&
          ?end >= "2009-01-01T00:00:00Z"^^xsd:dateTime)
  ?player rdfs:label ?playerLabel .
  FILTER (LANG(?playerLabel) = "en")
}

